mapper.select:
SELECT e.id, e.user_id, e.login_account, e.id_card, e.address, e.branch_code, e.name, e.avatar_color, e.position, e.department, e.source, e.birthday, e.mobile, e.intern_date, e.hire_date, e.contract_status, e.salary_base, e.deposit_amount, e.status, e.resign_date, e.remark, e.create_by, e.create_time, e.update_by, e.update_time, u.login_ip, u.login_date FROM biz_employee e LEFT JOIN sys_user u ON e.user_id = u.user_id
AND e.branch_code = #{branchCode}
AND e.name LIKE CONCAT('%', #{name}, '%')
AND e.id_card LIKE CONCAT('%', #{idCard}, '%')
AND e.mobile LIKE CONCAT('%', #{mobile}, '%')
AND e.position LIKE CONCAT('%', #{position}, '%')
AND e.department = #{department}
AND e.status = #{status}
AND e.login_account LIKE CONCAT('%', #{loginAccount}, '%')
ORDER BY e.create_time DESC

mapper.update:
UPDATE biz_employee
user_id = #{userId}, login_account = #{loginAccount}, id_card = #{idCard}, address = #{address}, name = #{name}, avatar_color = #{avatarColor}, position = #{position}, department = #{department}, source = #{source}, birthday = #{birthday}, mobile = #{mobile}, intern_date = #{internDate}, hire_date = #{hireDate}, contract_status = #{contractStatus}, salary_base = #{salaryBase}, deposit_amount = #{depositAmount}, status = #{status}, resign_date = #{resignDate}, remark = #{remark}, update_by = #{updateBy}, update_time = NOW()
WHERE id = #{id}
